import React, { useState } from 'react';
import './HotelCard.css';

function HotelCard({ hotel, onBook }) {
  const [showBookingForm, setShowBookingForm] = useState(false);
  const [checkIn, setCheckIn] = useState('');
  const [checkOut, setCheckOut] = useState('');

  const handleBook = () => {
    // BUG: No validation - can book unavailable hotels
    onBook(hotel.id, checkIn, checkOut);
    setShowBookingForm(false);
    setCheckIn('');
    setCheckOut('');
  };

  return (
    <div className="hotel-card">
      <div className="hotel-header">
        <h3>{hotel.name}</h3>
        <span className="rating">⭐ {hotel.rating}</span>
      </div>

      <div className="hotel-details">
        <p><strong>📍 City:</strong> {hotel.city}</p>
        <p><strong>💰 Price:</strong> ${hotel.price} per night</p>
        <p>
          <strong>Available:</strong>{' '}
          {/* BUG: Shows availability but booking still works regardless */}
          <span className={hotel.available ? 'available' : 'unavailable'}>
            {hotel.available ? '✓ Yes' : '✗ No'}
          </span>
        </p>
      </div>

      {!showBookingForm ? (
        <button
          onClick={() => setShowBookingForm(true)}
          disabled={!hotel.available}
          className={hotel.available ? '' : 'disabled'}
        >
          {hotel.available ? 'Book Now' : 'Unavailable'}
        </button>
      ) : (
        <div className="booking-form">
          <div className="form-group">
            <label>Check-in Date</label>
            <input
              type="date"
              value={checkIn}
              onChange={(e) => setCheckIn(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Check-out Date</label>
            <input
              type="date"
              value={checkOut}
              onChange={(e) => setCheckOut(e.target.value)}
            />
          </div>

          <div className="booking-actions">
            <button onClick={handleBook} className="confirm">
              Confirm Booking
            </button>
            <button
              onClick={() => setShowBookingForm(false)}
              className="cancel"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default HotelCard;
